import { Component } from "react";

class RedesSocial extends Component {
    render(){
        const { x } = this.props
        return(
            <div className="redSocial">
                <a className="enlace-red-social" href={x.enlace}>
                    <img className='logo' alt={x.nombre} src={x.img}/>
                </a>
                <h2 className="nombre-red-social">{x.nombre}</h2>
            </div>
        )
    }
}
